import { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import { motion } from 'framer-motion';
import { propertiesData } from '../data/propertiesData';
import { 
  Heart, Share2, MapPin, Ruler, Bath, Bed, Car, 
  CheckCircle, Shield, Calendar, Building2, 
  Wifi, Lock, Camera, ChevronLeft, ChevronRight, 
  Waves, Dumbbell, Coffee, Trees, Users, Home,
  DollarSign, TrendingUp, Key, Maximize2, Phone, Mail
} from 'lucide-react';

const PropertyDetails = () => {
  const { id } = useParams();
  const [property, setProperty] = useState(null);
  const [loading, setLoading] = useState(true);
  const [currentImage, setCurrentImage] = useState(0);
  const [isFavorite, setIsFavorite] = useState(false);
  const [showEnquiryForm, setShowEnquiryForm] = useState(false);

  useEffect(() => {
    // Find property by ID from our data
    const foundProperty = propertiesData.find(p => p.id === id);
    setProperty(foundProperty);
    setLoading(false);
  }, [id]);

  const formatPrice = (price, listingType) => {
    if (listingType === 'Rent') {
      return `₹${price.toLocaleString('en-IN')}/month`;
    }
    if (listingType === 'Lease') {
      return `₹${price.toLocaleString('en-IN')}/year`;
    }
    if (price >= 10000000) return `₹${(price / 10000000).toFixed(2)} Cr`;
    if (price >= 100000) return `₹${(price / 100000).toFixed(1)} Lakhs`;
    return `₹${price.toLocaleString('en-IN')}`;
  };

  const getListingTypeColor = (type) => {
    switch(type) {
      case 'Sale': return 'bg-green-100 text-green-700';
      case 'Rent': return 'bg-blue-100 text-blue-700';
      case 'Lease': return 'bg-purple-100 text-purple-700';
      default: return 'bg-gray-100 text-gray-700';
    }
  };

  const amenityIcons = {
    "Swimming Pool": Waves,
    "Gymnasium": Dumbbell,
    "Club House": Home,
    "Cafeteria": Coffee,
    "High-Speed WiFi": Wifi,
    "24/7 Security": Lock,
    "CCTV Surveillance": Camera,
    "Power Backup": Building2,
    "Landscaped Garden": Trees,
    "Children's Play Area": Users,
    "Private Garden": Trees,
    "Terrace": Home,
    "Car Parking": Car,
    "Security System": Shield,
    "Private Pool": Waves,
    "Home Theater": Tv,
    "Staff Room": Users,
    "Lift": Building2,
    "Water Supply": Waves,
    "Farm Area": Trees,
    "Well": Waves,
    "AC": Wind,
    "Meeting Room": Users,
    "Pantry": Coffee,
    "Glass Facade": Building2,
    "Storage": Home,
    "Loading Dock": Car,
    "24/7 Access": Clock,
    "Lighting": Sun
  };

  const getAmenityIcon = (amenity) => {
    const Icon = amenityIcons[amenity] || Building2;
    return <Icon size={18} className="text-[#d4af37]" />;
  };

  if (loading) {
    return (
      <div className="pt-32 min-h-screen flex items-center justify-center">
        <div className="animate-spin rounded-full h-16 w-16 border-b-2 border-[#d4af37] mx-auto"></div>
      </div>
    );
  }

  if (!property) {
    return (
      <div className="pt-32 min-h-screen flex items-center justify-center">
        <div className="text-center">
          <p className="text-gray-500">Property not found</p>
          <Link to="/projects" className="text-[#d4af37] hover:underline mt-2 inline-block">
            ← Back to Properties
          </Link>
        </div>
      </div>
    );
  }

  return (
    <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="pt-24 pb-16 bg-gray-50">
      <div className="container-custom">
        {/* Breadcrumb */}
        <div className="mb-6">
          <Link to="/" className="text-gray-500 hover:text-[#d4af37] text-sm">Home</Link>
          <span className="text-gray-400 mx-2">/</span>
          <Link to="/projects" className="text-gray-500 hover:text-[#d4af37] text-sm">Properties</Link>
          <span className="text-gray-400 mx-2">/</span>
          <span className="text-[#d4af37] text-sm">{property.title}</span>
        </div>

        <div className="grid lg:grid-cols-3 gap-8">
          {/* Images Gallery */}
          <div className="lg:col-span-2">
            <div className="relative bg-black rounded-2xl overflow-hidden mb-4">
              <img src={property.images[currentImage]} alt={property.title} className="w-full h-[500px] object-cover" />
              {property.images.length > 1 && (
                <>
                  <button onClick={() => setCurrentImage(prev => (prev - 1 + property.images.length) % property.images.length)} className="absolute left-4 top-1/2 transform -translate-y-1/2 bg-black/50 text-white p-2 rounded-full hover:bg-black/70">
                    <ChevronLeft size={24} />
                  </button>
                  <button onClick={() => setCurrentImage(prev => (prev + 1) % property.images.length)} className="absolute right-4 top-1/2 transform -translate-y-1/2 bg-black/50 text-white p-2 rounded-full hover:bg-black/70">
                    <ChevronRight size={24} />
                  </button>
                </>
              )}
            </div>
            
            <div className="flex gap-3 overflow-x-auto pb-2">
              {property.images.map((img, idx) => (
                <button key={idx} onClick={() => setCurrentImage(idx)} className={`w-20 h-16 rounded-lg overflow-hidden border-2 transition ${currentImage === idx ? 'border-[#d4af37]' : 'border-transparent'}`}>
                  <img src={img} alt="" className="w-full h-full object-cover" />
                </button>
              ))}
            </div>

            <div className="mt-8 bg-white rounded-2xl p-6">
              <h2 className="text-2xl font-bold mb-4">Description</h2>
              <p className="text-gray-600 leading-relaxed whitespace-pre-line">{property.description}</p>
            </div>

            {property.amenities && property.amenities.length > 0 && (
              <div className="mt-6 bg-white rounded-2xl p-6">
                <h2 className="text-2xl font-bold mb-4">Amenities</h2>
                <div className="grid grid-cols-2 md:grid-cols-3 gap-3">
                  {property.amenities.map((amenity, idx) => (
                    <div key={idx} className="flex items-center gap-2 p-2 bg-gray-50 rounded-lg">
                      {getAmenityIcon(amenity)}
                      <span className="text-sm text-gray-700">{amenity}</span>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>

          {/* Property Info Sidebar */}
          <div>
            <div className="bg-white rounded-2xl shadow-lg p-6 sticky top-24">
              <div className="flex justify-between items-start mb-3">
                <h1 className="text-2xl font-bold text-[#0a192f]">{property.title}</h1>
                <button onClick={() => setIsFavorite(!isFavorite)} className="p-2 rounded-full hover:bg-gray-100">
                  <Heart size={22} className={isFavorite ? 'text-red-500 fill-red-500' : 'text-gray-400'} />
                </button>
              </div>
              
              <div className="flex items-center gap-2 mb-4">
                <MapPin size={16} className="text-gray-400" />
                <p className="text-gray-500 text-sm">{property.location}</p>
              </div>

              <div className="mb-4">
                <span className="text-3xl font-bold text-[#d4af37]">{formatPrice(property.price, property.listingType)}</span>
                {property.originalPrice && <span className="text-gray-400 line-through ml-2 text-sm">{formatPrice(property.originalPrice, property.listingType)}</span>}
              </div>

              <div className="flex flex-wrap gap-2 mb-6">
                <span className={`${getListingTypeColor(property.listingType)} px-3 py-1 rounded-full text-xs font-semibold`}>
                  {property.listingType}
                </span>
                <span className="bg-gray-100 text-gray-700 px-3 py-1 rounded-full text-xs font-semibold">{property.category}</span>
                <span className="bg-gray-100 text-gray-700 px-3 py-1 rounded-full text-xs font-semibold">{property.propertyType}</span>
                {property.reraVerified && <span className="bg-yellow-100 text-yellow-700 px-3 py-1 rounded-full text-xs font-semibold flex items-center gap-1"><Shield size={12} /> RERA</span>}
                {property.governmentVerified && <span className="bg-green-100 text-green-700 px-3 py-1 rounded-full text-xs font-semibold flex items-center gap-1"><CheckCircle size={12} /> Govt Verified</span>}
              </div>

              <div className="border-t border-b py-4 mb-6">
                <h3 className="font-semibold mb-3">Key Specifications</h3>
                <div className="grid grid-cols-2 gap-3">
                  {property.bedrooms > 0 && <div className="flex items-center gap-2"><Bed size={18} className="text-gray-400" /><span className="text-sm">{property.bedrooms} BHK</span></div>}
                  {property.specifications?.bathrooms && <div className="flex items-center gap-2"><Bath size={18} className="text-gray-400" /><span className="text-sm">{property.specifications.bathrooms} Bathrooms</span></div>}
                  <div className="flex items-center gap-2"><Ruler size={18} className="text-gray-400" /><span className="text-sm">{property.area_sqft} sq.ft</span></div>
                  {property.specifications?.carParking && <div className="flex items-center gap-2"><Car size={18} className="text-gray-400" /><span className="text-sm">{property.specifications.carParking} Parking</span></div>}
                  {property.specifications?.furnishing && <div className="flex items-center gap-2"><Home size={18} className="text-gray-400" /><span className="text-sm">{property.specifications.furnishing}</span></div>}
                  {property.specifications?.floor && <div className="flex items-center gap-2"><Building2 size={18} className="text-gray-400" /><span className="text-sm">Floor {property.specifications.floor}</span></div>}
                </div>
              </div>

              <button onClick={() => setShowEnquiryForm(!showEnquiryForm)} className="w-full bg-[#d4af37] text-[#0a192f] py-3 rounded-lg font-semibold hover:bg-opacity-90 transition mb-3">
                📞 Enquire Now
              </button>

              <Link to={`/contact?property=${property.title}`}>
                <button className="w-full border-2 border-[#d4af37] text-[#d4af37] py-3 rounded-lg font-semibold hover:bg-[#d4af37] hover:text-[#0a192f] transition">
                  Request Site Visit
                </button>
              </Link>

              {showEnquiryForm && (
                <div className="mt-4 p-4 bg-gray-50 rounded-lg">
                  <h4 className="font-semibold mb-3">Quick Enquiry for {property.title}</h4>
                  <input type="text" placeholder="Your Name" className="w-full p-2 border rounded-lg mb-2" />
                  <input type="tel" placeholder="Phone Number" className="w-full p-2 border rounded-lg mb-2" />
                  <input type="email" placeholder="Email ID" className="w-full p-2 border rounded-lg mb-3" />
                  <button className="w-full bg-[#d4af37] text-[#0a192f] py-2 rounded-lg font-semibold">Submit Enquiry</button>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>
    </motion.div>
  );
};

export default PropertyDetails;
